1	"use client";
2	
3	import { useEffect, useState } from "react";
4	import { useRouter } from "next/navigation";
5	import { useAuth } from "@/lib/auth-context";
6	import { apiFetch, type PaginatedResponse } from "@/lib/api-client";
7	import { Button } from "@/components/ui/button";
8	
9	interface ApprovalTicket {
10	  id: string;
11	  type: string;
12	  status: string;
13	  reason: string;
14	  createdAt: string;
15	  applicant: { id: string; name: string; email: string };
16	  targetModel?: { modelName: string; brandName: string };
17	  targetAsset?: { id: string; model?: { modelName: string } };
18	}
19	
20	export default function ApprovalsPage() {
21	  const { user } = useAuth();
22	  const router = useRouter();
23	  const [tab, setTab] = useState<"pending" | "history">("pending");
24	  const [tickets, setTickets] = useState<ApprovalTicket[]>([]);
25	  const [page, setPage] = useState(1);
26	  const [totalPages, setTotalPages] = useState(1);
27	  const [loading, setLoading] = useState(true);
28	  const [error, setError] = useState<string | null>(null);
29	  const [approveLoading, setApproveLoading] = useState("");
30	  const [rejectDialog, setRejectDialog] = useState<{ id: string } | null>(null);
31	  const [rejectReason, setRejectReason] = useState("");
32	  const [deputyMode, setDeputyMode] = useState(false);
33	
34	  const fetchApprovals = async (p: number) => {
35	    setLoading(true);
36	    setError(null);
37	    try {
38	      const endpoint = tab === "pending" ? "/api/approvals/pending" : "/api/approvals/history";
39	      const res = await apiFetch<PaginatedResponse<ApprovalTicket>>(endpoint, {
40	        params: { page: p, pageSize: 20 },
41	      });
42	      setTickets(res.data);
43	      setTotalPages(res.pagination.totalPages);
44	      setPage(res.pagination.page);
45	    } catch (err) {
46	      setError(err instanceof Error ? err.message : "加载失败");
47	    } finally {
48	      setLoading(false);
49	    }
50	  };
51	
52	  useEffect(() => {
53	    fetchApprovals(1);
54	  }, [tab]);
55	
56	  const handleApprove = async (id: string) => {
57	    setApproveLoading(id);
58	    try {
59	      const body: Record<string, unknown> = {};
60	      if (deputyMode) body.deputy = true;
61	      await apiFetch(`/api/tickets/${id}/approve`, { method: "POST", body });
62	      await fetchApprovals(page);
63	    } catch (err) {
64	      setError(err instanceof Error ? err.message : "操作失败");
65	    } finally {
66	      setApproveLoading("");
67	    }
68	  };
69	
70	  const handleReject = async () => {
71	    if (!rejectDialog || !rejectReason.trim()) return;
72	    setApproveLoading(rejectDialog.id);
73	    try {
74	      await apiFetch(`/api/tickets/${rejectDialog.id}/reject`, {
75	        method: "POST",
76	        body: { rejectReason },
77	      });
78	      setRejectDialog(null);
79	      setRejectReason("");
80	      await fetchApprovals(page);
81	    } catch (err) {
82	      setError(err instanceof Error ? err.message : "操作失败");
83	    } finally {
84	      setApproveLoading("");
85	    }
86	  };
87	
88	  const typeLabel = (type: string) => {
89	    const map: Record<string, string> = { APPLY: "申领", REPAIR: "报修", RETURN: "归还", TRANSFER: "调拨" };
90	    return map[type] ?? type;
91	  };
92	
93	  const statusBadge = (status: string) => {
94	    const map: Record<string, string> = {
95	      PENDING_MANAGER_1: "bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-400",
96	      PENDING_MANAGER_2: "bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-400",
97	      PENDING_IT: "bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400",
98	      APPROVED: "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400",
99	      REJECTED: "bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400",
100	      COMPLETED: "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400",
101	      CANCELLED: "bg-gray-100 text-gray-800 dark:bg-gray-900/30 dark:text-gray-400",
102	    };
103	    const label: Record<string, string> = {
104	      PENDING_MANAGER_1: "待审批", PENDING_MANAGER_2: "待审批",
105	      PENDING_IT: "待IT处理", APPROVED: "已通过",
106	      REJECTED: "已驳回", COMPLETED: "已完成", CANCELLED: "已取消",
107	    };
108	    return (
109	      <span className={`rounded-full px-2 py-0.5 text-xs font-medium ${map[status] ?? ""}`}>
110	        {label[status] ?? status}
111	      </span>
112	    );
113	  };
114	
115	  if (!user) return null;
116	  if (!["MANAGER", "IT_ADMIN"].includes(user.role)) {
117	    return (
118	      <div className="flex flex-1 items-center justify-center p-4">
119	        <p className="text-muted-foreground">你无权访问此页面</p>
120	      </div>
121	    );
122	  }
123	
124	  if (loading) {
125	    return (
126	      <div className="flex flex-1 items-center justify-center p-4">
127	        <div className="w-full max-w-4xl space-y-4">
128	          <div className="h-8 w-32 animate-pulse rounded bg-muted" />
129	          <div className="flex gap-2">
130	            <div className="h-9 w-24 animate-pulse rounded bg-muted" />
131	            <div className="h-9 w-24 animate-pulse rounded bg-muted" />
132	          </div>
133	          {[1, 2, 3].map((i) => (
134	            <div key={i} className="h-20 animate-pulse rounded-lg bg-muted" />
135	          ))}
136	        </div>
137	      </div>
138	    );
139	  }
140	
141	  if (error !== null) {
142	    return (
143	      <div className="flex flex-1 flex-col items-center justify-center gap-4 p-4">
144	        <p className="text-destructive">{error}</p>
145	        <Button onClick={() => fetchApprovals(1)}>重试</Button>
146	      </div>
147	    );
148	  }
149	
150	  return (
151	    <div className="flex flex-1 flex-col gap-6 p-4 max-w-4xl mx-auto w-full">
152	      <h1 className="text-2xl font-bold">审批管理</h1>
153	
154	      {/* Tabs */}
155	      <div className="flex gap-2">
156	        <Button variant={tab === "pending" ? "default" : "outline"} onClick={() => setTab("pending")}>
157	          待审批
158	        </Button>
159	        <Button variant={tab === "history" ? "default" : "outline"} onClick={() => setTab("history")}>
160	          已审批
161	        </Button>
162	      </div>
163	
164	      {/* Deputy mode toggle (IT_ADMIN only) */}
165	      {user.role === "IT_ADMIN" && tab === "pending" && (
166	        <label className="flex items-center gap-2 text-sm">
167	          <input type="checkbox" checked={deputyMode} onChange={(e) => setDeputyMode(e.target.checked)} />
168	          代审批模式
169	        </label>
170	      )}
171	
172	      {tickets.length === 0 ? (
173	        <div className="rounded-lg border border-dashed p-12 text-center">
174	          <p className="text-muted-foreground">
175	            {tab === "pending" ? "暂无待审批的工单" : "暂无审批记录"}
176	          </p>
177	        </div>
178	      ) : (
179	        <>
180	          <div className="space-y-2">
181	            {tickets.map((t) => (
182	              <div key={t.id} className="rounded-lg border p-4">
183	                <div className="flex items-start justify-between">
184	                  <div className="flex-1">
185	                    <div className="flex items-center gap-2">
186	                      <span className="font-medium">{typeLabel(t.type)}</span>
187	                      <span className="text-sm text-muted-foreground">
188	                        {t.applicant.name}
189	                      </span>
190	                      {statusBadge(t.status)}
191	                    </div>
192	                    <p className="mt-1 text-sm text-muted-foreground line-clamp-1">{t.reason}</p>
193	                    <p className="mt-1 text-xs text-muted-foreground">
194	                      {new Date(t.createdAt).toLocaleString("zh-CN")}
195	                    </p>
196	                  </div>
197	                  <div className="flex items-center gap-2 ml-4">
198	                    <Button
199	                      size="sm"
200	                      onClick={() => router.push(`/tickets/${t.id}`)}
201	                      variant="outline"
202	                    >
203	                      详情
204	                    </Button>
205	                    {tab === "pending" && (
206	                      <>
207	                        <Button
208	                          size="sm"
209	                          onClick={() => handleApprove(t.id)}
210	                          disabled={approveLoading === t.id}
211	                        >
212	                          {approveLoading === t.id ? "..." : "通过"}
213	                        </Button>
214	                        <Button
215	                          size="sm"
216	                          variant="destructive"
217	                          onClick={() => setRejectDialog({ id: t.id })}
218	                          disabled={approveLoading === t.id}
219	                        >
220	                          驳回
221	                        </Button>
222	                      </>
223	                    )}
224	                  </div>
225	                </div>
226	              </div>
227	            ))}
228	          </div>
229	
230	          {totalPages > 1 && (
231	            <div className="flex items-center justify-center gap-2">
232	              <Button variant="outline" disabled={page <= 1} onClick={() => fetchApprovals(page - 1)}>
233	                上一页
234	              </Button>
