289	function ActionDialog({
290	  title,
291	  reason,
292	  setReason,
293	  onConfirm,
294	  onCancel,
295	  loading,
296	}: {
297	  title: string;
298	  reason: string;
299	  setReason: (v: string) => void;
300	  onConfirm: () => void;
301	  onCancel: () => void;
302	  loading: boolean;
303	}) {
304	  return (
305	    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
306	      <div className="w-full max-w-sm rounded-lg bg-background p-6 space-y-4">
