308	        <textarea
309	          value={reason}
310	          onChange={(e) => setReason(e.target.value)}
311	          placeholder="请输入原因..."
312	          rows={3}
313	          className="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50"
314	        />
315	        <div className="flex justify-end gap-2">
316	          <Button variant="outline" onClick={onCancel}>取消</Button>
317	          <Button onClick={onConfirm} disabled={!reason.trim() || loading}>
318	            {loading ? "处理中..." : "确认"}
319	          </Button>
