"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/lib/auth-context";
import { apiFetch, type PaginatedResponse } from "@/lib/api-client";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { Textarea } from "@/components/ui/textarea";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { EmptyState } from "@/components/empty-state";
import { TicketStatusBadge } from "@/components/ticket-status-badge";
import { PageHeader } from "@/components/page-header";
import { Inbox } from "lucide-react";

interface ApprovalTicket {
  id: string;
  type: string;
  status: string;
  reason: string;
  createdAt: string;
  applicant: { id: string; name: string; email: string };
  targetModel?: { modelName: string; brandName: string };
  targetAsset?: { id: string; model?: { modelName: string } };
}

export default function ApprovalsPage() {
  const { user } = useAuth();
  const router = useRouter();
  const [tab, setTab] = useState<"pending" | "history">("pending");
  const [tickets, setTickets] = useState<ApprovalTicket[]>([]);
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [approveLoading, setApproveLoading] = useState("");
  const [rejectDialog, setRejectDialog] = useState<{ id: string } | null>(null);
  const [rejectReason, setRejectReason] = useState("");
  const [deputyMode, setDeputyMode] = useState(false);

  const fetchApprovals = async (p: number) => {
    setLoading(true);
    setError(null);
    try {
      const endpoint = tab === "pending" ? "/api/approvals/pending" : "/api/approvals/history";
      const res = await apiFetch<PaginatedResponse<ApprovalTicket>>(endpoint, {
        params: { page: p, pageSize: 20 },
      });
      setTickets(res.data);
      setTotalPages(res.pagination.totalPages);
      setPage(res.pagination.page);
    } catch (err) {
      setError(err instanceof Error ? err.message : "加载失败");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchApprovals(1);
  }, [tab]);

  const handleApprove = async (id: string) => {
    setApproveLoading(id);
    try {
      const body: Record<string, unknown> = {};
      if (deputyMode) body.deputy = true;
      await apiFetch(`/api/tickets/${id}/approve`, { method: "POST", body });
      await fetchApprovals(page);
    } catch (err) {
      setError(err instanceof Error ? err.message : "操作失败");
    } finally {
      setApproveLoading("");
    }
  };

  const handleReject = async () => {
    if (!rejectDialog || !rejectReason.trim()) return;
    setApproveLoading(rejectDialog.id);
    try {
      await apiFetch(`/api/tickets/${rejectDialog.id}/reject`, {
        method: "POST",
        body: { rejectReason },
      });
      setRejectDialog(null);
      setRejectReason("");
      await fetchApprovals(page);
    } catch (err) {
      setError(err instanceof Error ? err.message : "操作失败");
    } finally {
      setApproveLoading("");
    }
  };

  const typeLabel = (type: string) => {
    const map: Record<string, string> = { APPLY: "申领", REPAIR: "报修", RETURN: "归还", TRANSFER: "调拨" };
    return map[type] ?? type;
  };

  if (!user) return null;
  if (!["MANAGER", "IT_ADMIN"].includes(user.role)) {
    return (
      <div className="flex flex-1 items-center justify-center p-4">
        <p className="text-muted-foreground">你无权访问此页面</p>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="flex flex-1 items-center justify-center p-4">
        <div className="w-full max-w-4xl space-y-4">
          <Skeleton className="h-8 w-32" />
          <div className="flex gap-2">
            <Skeleton className="h-9 w-24" />
            <Skeleton className="h-9 w-24" />
          </div>
          {[1, 2, 3].map((i) => (
            <Skeleton key={i} className="h-20" />
          ))}
        </div>
      </div>
    );
  }

  if (error !== null) {
    return (
      <div className="flex flex-1 flex-col items-center justify-center gap-4 p-4">
        <p className="text-destructive">{error}</p>
        <Button onClick={() => fetchApprovals(1)}>重试</Button>
      </div>
    );
  }

  return (
    <div className="flex flex-1 flex-col gap-6 p-4 max-w-4xl mx-auto w-full">
      <PageHeader title="待审批" description="处理部门员工的工单申请" />

      {/* Tabs */}
      <div className="flex gap-2">
        <Button variant={tab === "pending" ? "default" : "outline"} onClick={() => setTab("pending")}>
          待审批
        </Button>
        <Button variant={tab === "history" ? "default" : "outline"} onClick={() => setTab("history")}>
          已审批
        </Button>
      </div>

      {/* Deputy mode toggle (IT_ADMIN only) */}
      {user.role === "IT_ADMIN" && tab === "pending" && (
        <label className="flex items-center gap-2 text-sm">
          <input type="checkbox" checked={deputyMode} onChange={(e) => setDeputyMode(e.target.checked)} />
          代审批模式
        </label>
      )}

      {tickets.length === 0 ? (
        <EmptyState
          icon={Inbox}
          title={tab === "pending" ? "暂无待审批工单" : "暂无审批记录"}
        />
      ) : (
        <>
          <div className="space-y-2">
            {tickets.map((t) => (
              <div key={t.id} className="rounded-lg border p-4">
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      <span className="font-medium">{typeLabel(t.type)}</span>
                      <span className="text-sm text-muted-foreground">
                        {t.applicant.name}
                      </span>
                      <TicketStatusBadge status={t.status} />
                    </div>
                    <p className="mt-1 text-sm text-muted-foreground line-clamp-1">{t.reason}</p>
                    <p className="mt-1 text-xs text-muted-foreground">
                      {new Date(t.createdAt).toLocaleString("zh-CN")}
                    </p>
                  </div>
                  <div className="flex items-center gap-2 ml-4">
                    <Button
                      size="sm"
                      onClick={() => router.push(`/tickets/${t.id}`)}
                      variant="outline"
                    >
                      详情
                    </Button>
                    {tab === "pending" && (
                      <>
                        <Button
                          size="sm"
                          onClick={() => handleApprove(t.id)}
                          disabled={approveLoading === t.id}
                        >
                          {approveLoading === t.id ? "..." : "通过"}
                        </Button>
                        <Button
                          size="sm"
                          variant="destructive"
                          onClick={() => setRejectDialog({ id: t.id })}
                          disabled={approveLoading === t.id}
                        >
                          驳回
                        </Button>
                      </>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>

          {totalPages > 1 && (
            <div className="flex items-center justify-center gap-2">
              <Button variant="outline" disabled={page <= 1} onClick={() => fetchApprovals(page - 1)}>
                上一页
              </Button>
              <span className="text-sm text-muted-foreground">{page} / {totalPages}</span>
              <Button variant="outline" disabled={page >= totalPages} onClick={() => fetchApprovals(page + 1)}>
                下一页
              </Button>
            </div>
          )}
        </>
      )}

      {/* Reject Dialog */}
      <Dialog open={rejectDialog !== null} onOpenChange={(open) => { if (!open) { setRejectDialog(null); setRejectReason(""); } }}>
        <DialogContent showCloseButton>
          <DialogHeader>
            <DialogTitle>驳回工单</DialogTitle>
          </DialogHeader>
          <Textarea
            value={rejectReason}
            onChange={(e) => setRejectReason(e.target.value)}
            placeholder="请输入驳回原因..."
            rows={3}
          />
          <DialogFooter>
            <Button variant="outline" onClick={() => { setRejectDialog(null); setRejectReason(""); }}>
              取消
            </Button>
            <Button onClick={handleReject} disabled={!rejectReason.trim()}>
              确认驳回
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { useAuth } from "@/lib/auth-context";
import { apiFetch, type PaginatedResponse } from "@/lib/api-client";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { Card, CardContent } from "@/components/ui/card";
import { EmptyState } from "@/components/empty-state";
import { PageHeader } from "@/components/page-header";
import { Inbox } from "lucide-react";

interface TicketItem {
  id: string;
  type: string;
  status: string;
  reason: string;
  createdAt: string;
  applicant: { name: string };
}

export default function DeptBoardPage() {
  const { user } = useAuth();
  const [pendingCount, setPendingCount] = useState(0);
  const [recentTickets, setRecentTickets] = useState<TicketItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      const [pendingRes, recentRes] = await Promise.all([
        apiFetch<PaginatedResponse<TicketItem>>("/api/approvals/pending", {
          params: { page: 1, pageSize: 1 },
        }),
        apiFetch<PaginatedResponse<TicketItem>>("/api/approvals/history", {
          params: { page: 1, pageSize: 5 },
        }),
      ]);
      setPendingCount(pendingRes.pagination.total);
      setRecentTickets(recentRes.data);
    } catch (err) {
      setError(err instanceof Error ? err.message : "加载失败");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  if (!user) return null;
  if (user.role !== "MANAGER") {
    return (
      <div className="flex flex-1 items-center justify-center p-4">
        <p className="text-muted-foreground">仅主管可访问此页面</p>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="flex flex-1 items-center justify-center p-4">
        <div className="w-full max-w-4xl space-y-4">
          <Skeleton className="h-8 w-48" />
          <div className="grid grid-cols-3 gap-4">
            {[1, 2, 3].map((i) => (
              <Skeleton key={i} className="h-24" />
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (error !== null) {
    return (
      <div className="flex flex-1 flex-col items-center justify-center gap-4 p-4">
        <p className="text-destructive">{error}</p>
        <Button onClick={fetchData}>重试</Button>
      </div>
    );
  }

  return (
    <div className="flex flex-1 flex-col gap-6 p-4 max-w-4xl mx-auto w-full">
      <PageHeader title="部门看板" />

      {/* Stats */}
      <div className="grid grid-cols-3 gap-4">
        <Card>
          <CardContent>
            <p className="text-sm text-muted-foreground">待审批</p>
            <p className="text-3xl font-bold text-primary">{pendingCount}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent>
            <p className="text-sm text-muted-foreground">部门</p>
            <p className="text-lg font-medium">{user.department}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent>
            <p className="text-sm text-muted-foreground">角色</p>
            <p className="text-lg font-medium">主管</p>
          </CardContent>
        </Card>
      </div>

      {/* Quick Actions */}
      <div className="flex flex-wrap gap-2">
        <Link href="/approvals">
          <Button>审批管理</Button>
        </Link>
        <Link href="/my-assets">
          <Button variant="outline">部门资产</Button>
        </Link>
        <Link href="/tickets">
          <Button variant="outline">工单列表</Button>
        </Link>
      </div>

      {/* Recent */}
      <div>
        <h2 className="text-lg font-semibold mb-3">最近审批记录</h2>
        {recentTickets.length === 0 ? (
          <EmptyState icon={Inbox} title="暂无审批记录" />
        ) : (
          <div className="space-y-2">
            {recentTickets.map((t) => (
              <Link
                key={t.id}
                href={`/tickets/${t.id}`}
