  }

  if (!asset) {
    return (
      <div className="flex flex-1 items-center justify-center p-4">
        <p className="text-muted-foreground">资产不存在</p>
      </div>
    );
  }

  return (
    <div className="flex flex-1 flex-col gap-6 p-4 max-w-3xl mx-auto w-full">
      <div className="flex items-center justify-between">
        <div>
          <PageHeader title={`${asset.model.brandName} ${asset.model.modelName}`} />
          <p className="text-sm text-muted-foreground font-mono">{asset.sn}</p>
        </div>
        <AssetStatusBadge status={asset.status as import("@/components/asset-status-badge").AssetInstanceStatus} />
      </div>

      {/* Detail Grid */}
      <div className="grid grid-cols-2 gap-4">
        <Card>
          <CardContent>
            <p className="text-xs text-muted-foreground">资产 ID</p>
            <p className="text-sm font-mono">{asset.id}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent>
            <p className="text-xs text-muted-foreground">分类</p>
            <p className="text-sm">{asset.model.category}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent>
            <p className="text-xs text-muted-foreground">持有人</p>
            <p className="text-sm">{asset.holder?.name ?? "-"}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent>
            <p className="text-xs text-muted-foreground">部门</p>
            <p className="text-sm">{asset.department?.name ?? "-"}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent>
            <p className="text-xs text-muted-foreground">采购日期</p>
            <p className="text-sm">{new Date(asset.purchaseDate).toLocaleDateString("zh-CN")}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent>
            <p className="text-xs text-muted-foreground">保修到期</p>
            <p className="text-sm">{new Date(asset.warrantyExpiry).toLocaleDateString("zh-CN")}</p>
          </CardContent>
        </Card>
      </div>

      {/* Actions */}
      {asset.status !== "SCRAPPED" && asset.status !== "LOST" && (
        <div className="flex gap-2">
          <Button variant="destructive" onClick={() => setScrapDialog(true)}>
            报废
          </Button>
          <Button variant="destructive" onClick={() => setLostDialog(true)}>
            标记丢失
          </Button>
        </div>
      )}

      {/* Related Tickets */}
      {asset.tickets && asset.tickets.length > 0 && (
        <div className="space-y-2">
          <h2 className="text-lg font-semibold">关联工单</h2>
          <div className="space-y-2">
            {asset.tickets.map((t) => (
              <div
                key={t.id}
                className="rounded-lg border p-3 transition-colors hover:bg-muted/50 cursor-pointer"
                onClick={() => router.push(`/tickets/${t.id}`)}
              >
                <div className="flex items-center justify-between">
                  <span className="text-sm font-medium">{t.type} - {t.applicant.name}</span>
                  <span className="text-xs text-muted-foreground">{t.status}</span>
                </div>
                <p className="text-sm text-muted-foreground line-clamp-1">{t.reason}</p>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Timeline */}
      <div className="space-y-2">
        <h2 className="text-lg font-semibold">生命周期</h2>
        {timeline.length === 0 ? (
          <div className="rounded-lg border border-dashed p-6 text-center text-sm text-muted-foreground">
            暂无记录
          </div>
        ) : (
          <div className="space-y-2">
            {timeline.map((entry) => (
              <div key={entry.id} className="flex items-start gap-3 rounded-lg border p-3">
                <div className="mt-1 h-2 w-2 rounded-full bg-primary shrink-0" />
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium">{entry.action}</p>
                  <p className="text-xs text-muted-foreground">
                    {entry.operator.name} - {new Date(entry.createdAt).toLocaleString("zh-CN")}
                  </p>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Scrap Dialog */}
      <Dialog open={scrapDialog} onOpenChange={(open) => { if (!open) { setScrapDialog(false); setActionReason(""); } }}>
        <DialogContent showCloseButton>
          <DialogHeader>
            <DialogTitle>报废资产</DialogTitle>
          </DialogHeader>
          <Textarea
            value={actionReason}
            onChange={(e) => setActionReason(e.target.value)}
            placeholder="请输入原因..."
            rows={3}
          />
          <DialogFooter>
            <Button variant="outline" onClick={() => { setScrapDialog(false); setActionReason(""); }}>
              取消
            </Button>
            <Button onClick={handleScrap} disabled={!actionReason.trim() || actionLoading === "scrap"}>
              {actionLoading === "scrap" ? "处理中..." : "确认"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Lost Dialog */}
      <Dialog open={lostDialog} onOpenChange={(open) => { if (!open) { setLostDialog(false); setActionReason(""); } }}>
        <DialogContent showCloseButton>
          <DialogHeader>
            <DialogTitle>标记丢失</DialogTitle>
          </DialogHeader>
          <Textarea
            value={actionReason}
            onChange={(e) => setActionReason(e.target.value)}
            placeholder="请输入原因..."
            rows={3}
          />
          <DialogFooter>
            <Button variant="outline" onClick={() => { setLostDialog(false); setActionReason(""); }}>
              取消
            </Button>
            <Button onClick={handleLost} disabled={!actionReason.trim() || actionLoading === "lost"}>
              {actionLoading === "lost" ? "处理中..." : "确认"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {error !== null && (
        <div className="rounded-lg bg-destructive/10 px-4 py-2 text-sm text-destructive">
          {error}
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useAuth } from "@/lib/auth-context";
import { apiFetch } from "@/lib/api-client";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { EmptyState } from "@/components/empty-state";
import { PageHeader } from "@/components/page-header";
import { Inbox } from "lucide-react";

interface ModelItem {
  id: string;
  category: string;
  brandName: string;
  modelName: string;
  specs: Record<string, unknown>;
  purchasePrice?: number;
  warrantyMonths: number;
  status: string;
  stock?: number;
}

export default function ItModelsPage() {
  const { user } = useAuth();
  const [models, setModels] = useState<ModelItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchModels = async () => {
    setLoading(true);
    setError(null);
    try {
      // Fetch all assets and derive model info
      const res = await apiFetch<{ data: ModelItem[] }>("/api/it/assets", {
        params: { page: 1, pageSize: 100 },
      });
      // Extract unique models from assets
      const modelMap = new Map<string, ModelItem>();
      for (const a of res.data) {
        const model = (a as unknown as { model: ModelItem }).model;
        if (model && !modelMap.has(model.id)) {
          modelMap.set(model.id, { ...model, stock: 0 });
        }
      }
      setModels(Array.from(modelMap.values()));
    } catch (err) {
      setError(err instanceof Error ? err.message : "加载失败");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (user?.role === "IT_ADMIN") fetchModels();
  }, []);

  if (!user) return null;
  if (user.role !== "IT_ADMIN") {
    return (
      <div className="flex flex-1 items-center justify-center p-4">
        <p className="text-muted-foreground">仅 IT 管理员可访问此页面</p>
      </div>
    );
  }

  const categoryLabel: Record<string, string> = {
    LAPTOP: "笔记本", MONITOR: "显示器", KEYBOARD: "键盘",
    MOUSE: "鼠标", HEADPHONE: "耳机", OTHER: "其他",
  };

  if (loading) {
    return (
      <div className="flex flex-1 items-center justify-center p-4">
        <div className="w-full max-w-4xl space-y-4">
          <Skeleton className="h-8 w-32" />
          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
            {[1, 2, 3, 4].map((i) => (
              <Skeleton key={i} className="h-32" />
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (error !== null) {
    return (
      <div className="flex flex-1 flex-col items-center justify-center gap-4 p-4">
        <p className="text-destructive">{error}</p>
        <Button onClick={fetchModels}>重试</Button>
      </div>
    );
  }

  return (
    <div className="flex flex-1 flex-col gap-6 p-4 max-w-4xl mx-auto w-full">
      <PageHeader title="型号管理" description="管理设备型号和规格" />

      {models.length === 0 ? (
        <EmptyState icon={Inbox} title="暂无型号数据" />
      ) : (
        <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
          {models.map((m) => (
            <div key={m.id} className="rounded-lg border p-4 space-y-2">
              <div className="flex items-start justify-between">
                <div>
                  <p className="font-medium">{m.brandName} {m.modelName}</p>
                  <p className="text-sm text-muted-foreground">
                    {categoryLabel[m.category] ?? m.category}
                  </p>
                </div>
                <span className="rounded-full bg-secondary px-2 py-0.5 text-xs">
                  {m.status}
                </span>
              </div>
              {m.purchasePrice !== undefined && (
                <p className="text-sm">
                  参考价格: ¥{Number(m.purchasePrice).toLocaleString()}
                </p>
              )}
              <p className="text-sm text-muted-foreground">
                保修: {m.warrantyMonths}个月
              </p>
              {m.stock !== undefined && (
                <p className="text-sm">
                  库存: <span className="font-medium">{m.stock}</span>
                </p>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

